				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				score := (newCost - oldCost) + 0.01*cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
			}
			// Rollback tentative insertion
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
